sql:
SELECT vehicle_type, toll_rate_multiplier
FROM vehicle_classifications
ORDER BY vehicle_type ASC;

SELECT location, COUNT(tollgate_id) AS number_of_tollgates
FROM tollgates
GROUP BY location;

SELECT tollgate_id, location, toll_rate
FROM tollgates
WHERE toll_rate > (SELECT AVG(toll_rate) FROM tollgates);

external_knowledge:
- "Recent toll records" refers to records from the last 3 time units based on the maximum time in the toll records; 
- "Adjusted average toll paid" is calculated as the average toll paid multiplied by the toll rate multiplier and adjusted by a factor that considers the presence of an ETC device and the proportion of admin users; 
- "North of latitude 41.9128 and west of longitude -76.9089" refers to a specific geographic region.

sql:
SELECT toll_rate 
FROM tollgates 
WHERE tollgate_id = 1;

SELECT DISTINCT v.vehicle_type, vc.toll_rate_multiplier AS toll_rate
FROM vehicles v
INNER JOIN vehicle_classifications vc ON v.vehicle_type = vc.vehicle_type;

SELECT payment_method, SUM(amount) AS total_amount
FROM toll_payments
GROUP BY payment_method;

external_knowledge:
- vehicle classification; refers to categorizing vehicles based on their types or weight classes;
- toll payments and toll records relationship; each toll record corresponds to a specific payment made by a vehicle;
- the toll rate multiplier for vehicle classification; affects the final toll amount a vehicle is charged.

sql:
SELECT strftime('%Y', payment_date) AS year, SUM(amount) AS total_amount
FROM toll_payments
GROUP BY strftime('%Y', payment_date);

SELECT tollgate_id, COUNT(record_id) AS record_count
FROM toll_records
GROUP BY tollgate_id;
